   629→  font-weight: 800; 
   630→  color: var(--text-muted); 
   631→  text-transform: uppercase; 
   632→  letter-spacing: 1px; 
   633→  margin-bottom: 12px;
   634→  display: block;
   635→}
   636→
   637→.insight-box { 
   638→  background: rgba(99, 102, 241, 0.08);
   639→  padding: 16px; 
   640→  border-radius: var(--radius-md); 
   641→  font-size: 13px; 
   642→  line-height: 1.6;
   643→  border-left: 4px solid var(--primary);
   644→  border: 1px solid var(--border-color);
   645→  color: var(--text-main);
   646→}
   647→
   648→.card.dark .insight-box {
   649→  color: #e2e8f0;
   650→}
   651→
   652→.ai-status { 
   653→  background: rgba(16, 185, 129, 0.08);
   654→  color: var(--success); 
   655→  padding: 14px 16px; 
   656→  border-radius: var(--radius-md); 
   657→  display: flex; 
   658→  align-items: center; 
   659→  gap: 12px; 
   660→  font-size: 13px; 
   661→  font-weight: 600;
   662→  border: 1px solid rgba(16, 185, 129, 0.15);
   663→}
   664→
   665→/* Progress Charts */
   666→.progress-grid { 
   667→  display: grid; 
   668→  grid-template-columns: 1fr 1.2fr; 
   669→  gap: 24px; 
   670→}
   671→
   672→@media (max-width: 768px) {
   673→  .progress-grid {
   674→    grid-template-columns: 1fr;
   675→  }
   676→}
   677→
   678→.chart-container { 
   679→  display: flex; 
   680→  flex-direction: column; 
   681→  align-items: center; 
   682→  justify-content: center; 
   683→  min-height: 160px; 
   684→}
   685→
   686→.donut-mock { 
   687→  width: 120px; 
   688→  height: 120px; 
   689→  border: 16px solid var(--primary); 
   690→  border-top-color: var(--warning); 
   691→  border-right-color: var(--success);
   692→  border-radius: 50%;
   693→  box-shadow: 0 4px 15px var(--primary-glow);
   694→  animation: spinSlow 30s linear infinite;
   695→}
   696→
   697→@keyframes spinSlow {
   698→  from { transform: rotate(0deg); }
   699→  to { transform: rotate(360deg); }
   700→}
   701→
   702→.priority-bars { 
   703→  display: flex; 
   704→  flex-direction: column; 
   705→  gap: 12px; 
   706→  width: 100%; 
   707→}
   708→
   709→.priority-row { 
   710→  display: grid; 
   711→  grid-template-columns: 80px 1fr 30px; 
   712→  align-items: center; 
   713→  gap: 12px; 
   714→  font-size: 11px; 
   715→  font-weight: 700;
   716→  color: var(--text-muted);
   717→}
   718→
   719→.progress-bar-bg { 
   720→  height: 8px; 
   721→  background: var(--bg); 
   722→  border-radius: 10px; 
   723→  overflow: hidden; 
   724→  position: relative;
   725→  border: 1px solid var(--border-color);
   726→}
   727→
   728→.progress-fill { 
   729→  height: 100%; 
   730→  border-radius: 10px;
   731→  background: linear-gradient(90deg, var(--primary) 0%, var(--primary-light) 100%);
   732→  box-shadow: 0 0 8px var(--primary-glow);
   733→}
   734→
   735→/* Buttons */
   736→.btn { 
   737→  padding: 10px 18px; 
   738→  border-radius: 10px; 
   739→  font-family: var(--font-title);
   740→  font-weight: 700; 
   741→  font-size: 11px; 
   742→  cursor: pointer; 
   743→  border: none; 
   744→  display: inline-flex;
   745→  align-items: center; 
   746→  gap: 8px; 
   747→  transition: var(--transition);
   748→  text-transform: uppercase;
   749→  letter-spacing: 0.5px;
   750→}
   751→
   752→.btn-primary { 
   753→  background: linear-gradient(135deg, var(--primary) 0%, var(--primary-dark) 100%);
   754→  color: #fff; 
   755→  box-shadow: 0 4px 12px var(--primary-glow);
   756→}
   757→
   758→.btn-primary:hover { 
   759→  transform: translateY(-1px);
   760→  box-shadow: 0 6px 18px rgba(99, 102, 241, 0.35);
   761→}
   762→
   763→.btn-primary:active {
   764→  transform: translateY(0);
   765→}
   766→
   767→.btn-outline { 
   768→  background: transparent;
   769→  border: 1px solid var(--border-color);
   770→  color: var(--text-main);
   771→}
   772→
   773→.btn-outline:hover {
   774→  border-color: var(--primary);
   775→  color: var(--primary);
   776→  background: rgba(99, 102, 241, 0.04);
   777→}
   778→
   779→/* Tables */
   780→.table-container { 
   781→  background: var(--card-bg); 
   782→  border-radius: var(--radius-md); 
   783→  overflow: hidden; 
   784→  box-shadow: var(--card-shadow);
   785→  border: 1px solid var(--border-color);
   786→  width: 100%;
   787→}
   788→
   789→.data-table { 
   790→  width: 100%; 
   791→  border-collapse: collapse; 
   792→  text-align: left;
   793→}
   794→
   795→.data-table th { 
   796→  padding: 14px 20px; 
   797→  background: var(--bg); 
   798→  color: var(--text-muted); 
   799→  font-size: 11px; 
   800→  font-weight: 800; 
   801→  text-transform: uppercase; 
   802→  letter-spacing: 0.5px;
   803→  border-bottom: 1px solid var(--border-color);
   804→}
   805→
   806→.data-table td { 
   807→  padding: 14px 20px; 
   808→  border-bottom: 1px solid var(--border-color); 
   809→  font-size: 13px; 
   810→  font-weight: 500; 
   811→  color: var(--text-main);
   812→}
   813→
   814→.data-table tr:hover {
   815→  background: rgba(0, 0, 0, 0.01);
   816→}
   817→
   818→[data-theme='dark'] .data-table tr:hover {
   819→  background: rgba(255, 255, 255, 0.01);
   820→}
   821→
   822→.data-table tr:last-child td { 
   823→  border-bottom: none; 
   824→}
   825→
   826→/* e-Time Calendar Grid */
   827→.calendar-header { 
   828→  background: linear-gradient(135deg, #090d16 0%, #1e293b 100%);
   829→  color: #fff; 
   830→  border-radius: var(--radius-lg) var(--radius-lg) 0 0; 
   831→  padding: 24px; 
   832→  display: flex; 
   833→  justify-content: space-between; 
   834→  align-items: center;
   835→  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
   836→}
   837→
   838→.month-title { 
   839→  font-family: var(--font-title);
   840→  font-size: 28px; 
   841→  font-weight: 800; 
   842→  margin: 0; 
   843→  line-height: 1;
   844→  letter-spacing: -0.5px;
   845→}
   846→
   847→.year-subtitle { 
   848→  font-size: 13px; 
   849→  color: rgba(255, 255, 255, 0.5); 
   850→  margin-top: 4px; 
   851→}
   852→
   853→.cal-controls { 
   854→  display: flex; 
   855→  align-items: center; 
   856→  gap: 12px; 
   857→}
   858→
   859→.cal-grid { 
   860→  display: grid; 
   861→  grid-template-columns: repeat(7, 1fr); 
   862→  border-radius: 0 0 var(--radius-lg) var(--radius-lg); 
   863→  overflow: hidden; 
   864→  border: 1px solid var(--border-color);
   865→  border-top: none;
   866→}
   867→
   868→.cal-day-header { 
   869→  padding: 12px; 
   870→  text-align: center; 
   871→  font-size: 11px; 
   872→  font-weight: 800; 
   873→  color: var(--text-muted); 
   874→  background: var(--bg);
   875→  text-transform: uppercase;
   876→  letter-spacing: 0.5px;
   877→  border-bottom: 1px solid var(--border-color);
   878→}
   879→
   880→.cal-cell { 
   881→  height: 90px; 
   882→  background: var(--card-bg); 
   883→  border: 1px solid var(--border-color);
   884→  padding: 8px; 
   885→  position: relative;
   886→  transition: var(--transition);
   887→  overflow-y: auto;
   888→}
   889→
   890→.cal-cell:hover {
   891→  background: var(--bg);
   892→}
   893→
   894→.cal-date { 
   895→  font-size: 12px; 
   896→  font-weight: 600; 
   897→  color: var(--text-muted); 
   898→}
   899→
   900→.cal-cell.today .cal-date { 
   901→  background: linear-gradient(135deg, var(--primary) 0%, var(--primary-light) 100%);
   902→  color: #fff; 
   903→  width: 24px; 
   904→  height: 24px; 
   905→  display: flex; 
   906→  align-items: center; 
   907→  justify-content: center; 
   908→  border-radius: 6px;
   909→  font-weight: 700;
   910→  box-shadow: 0 2px 8px var(--primary-glow);
   911→}
   912→
   913→/* Badges */
   914→.badge { 
   915→  padding: 4px 8px; 
   916→  border-radius: 6px; 
   917→  font-size: 10px; 
   918→  font-weight: 700; 
   919→  text-transform: uppercase;
   920→  letter-spacing: 0.5px;
   921→  display: inline-block;
   922→}
   923→
   924→.badge-pending, .badge.pending, .badge.in_progress { 
   925→  background: var(--primary-glow);
   926→  color: var(--primary);
   927→  border: 1px solid rgba(99, 102, 241, 0.15);
   928→}
   929→
   930→.badge-success, .badge.success, .badge.completed {
   931→  background: var(--success-glow);
   932→  color: var(--success);
   933→  border: 1px solid rgba(16, 185, 129, 0.15);
   934→}
   935→
   936→.badge-warning, .badge.warning {
   937→  background: var(--warning-glow);
   938→  color: var(--warning);
   939→  border: 1px solid rgba(245, 158, 11, 0.15);
   940→}
   941→
   942→.badge-error, .badge.error, .badge.overdue {
   943→  background: var(--error-glow);
   944→  color: var(--error);
   945→  border: 1px solid rgba(239, 68, 68, 0.15);
   946→}
   947→
   948→/* Form Elements */
   949→input, select, textarea {
   950→  background: var(--card-bg);
   951→  border: 1px solid var(--border-color);
   952→  border-radius: 8px;
   953→  padding: 10px 14px;
   954→  color: var(--text-main);
   955→  font-size: 13px;
   956→  font-family: inherit;
   957→  transition: var(--transition);
   958→}
   959→
   960→input:focus, select:focus, textarea:focus {
   961→  outline: none;
   962→  border-color: var(--primary);
   963→  box-shadow: 0 0 0 3px var(--primary-glow);
   964→}
   965→
   966→input::placeholder, textarea::placeholder {
   967→  color: var(--text-muted);
   968→}
   969→
   970→/* Icons */
   971→.icon-africa { 
   972→  filter: grayscale(1) invert(0); 
   973→}
   974→
   975→[data-theme='dark'] .icon-africa {
   976→  filter: grayscale(1) invert(1);
   977→}
