arguments.content:
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');

:root {
  --font-title: 'Inter', sans-serif;
  --font-body: 'Plus Jakarta Sans', sans-serif;

  --primary: #6366f1;
  --primary-hover: #4f46e5;
  --primary-light: #818cf8;
  --primary-glow: rgba(99, 102, 241, 0.18);
  --primary-subtle: rgba(99, 102, 241, 0.07);

  --success: #10b981;
  --success-glow: rgba(16, 185, 129, 0.15);
  --success-subtle: rgba(16, 185, 129, 0.07);

  --warning: #f59e0b;
  --warning-glow: rgba(245, 158, 11, 0.15);
  --warning-subtle: rgba(245, 158, 11, 0.08);

  --error: #ef4444;
  --error-glow: rgba(239, 68, 68, 0.15);
  --error-subtle: rgba(239, 68, 68, 0.07);

  --purple: #8b5cf6;
  --cyan: #06b6d4;
  --orange: #f97316;
  --pink: #ec4899;

  --bg: #f1f5f9;
  --bg-alt: #e8edf3;
  --card-bg: #ffffff;
  --card-bg-hover: #fafbfe;
  --topbar-bg: rgba(255, 255, 255, 0.85);
  --sidebar-bg: #0c111d;
  --sidebar-item-hover: rgba(255, 255, 255, 0.06);
  --sidebar-item-active: rgba(99, 102, 241, 0.14);
  --sidebar-border: rgba(255, 255, 255, 0.06);

  --text-main: #0f172a;
  --text-sub: #334155;
  --text-muted: #64748b;
  --text-faint: #94a3b8;
  --border-color: #e2e8f0;
  --border-strong: #cbd5e1;
  --input-bg: #f8fafc;

  --card-shadow: 0 1px 4px rgba(15, 23, 42, 0.04), 0 4px 16px rgba(15, 23, 42, 0.04);
  --card-shadow-md: 0 4px 16px rgba(15, 23, 42, 0.06), 0 1px 3px rgba(15, 23, 42, 0.04);
  --card-shadow-hover: 0 8px 30px rgba(15, 23, 42, 0.1), 0 1px 4px rgba(15, 23, 42, 0.04);
  --modal-shadow: 0 24px 64px rgba(15, 23, 42, 0.18);

  --transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  --transition-fast: all 0.12s cubic-bezier(0.4, 0, 0.2, 1);

  --radius-xs: 6px;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --radius-full: 9999px;

  --sidebar-width: 248px;
}

[data-theme='dark'] {
  --bg: #090d18;
  --bg-alt: #0f1526;
  --card-bg: #111827;
  --card-bg-hover: #141e33;
  --topbar-bg: rgba(11, 15, 30, 0.85);
  --sidebar-bg: #070b14;
  --sidebar-border: rgba(255, 255, 255, 0.05);
  --sidebar-item-hover: rgba(255, 255, 255, 0.05);
  --sidebar-item-active: rgba(99, 102, 241, 0.16);

  --text-main: #f1f5f9;
  --text-sub: #cbd5e1;
  --text-muted: #94a3b8;
  --text-faint: #475569;
  --border-color: rgba(255, 255, 255, 0.07);
  --border-strong: rgba(255, 255, 255, 0.12);
  --input-bg: rgba(255, 255, 255, 0.04);

  --card-shadow: 0 4px 20px rgba(0, 0, 0, 0.25);
  --card-shadow-md: 0 6px 24px rgba(0, 0, 0, 0.3);
  --card-shadow-hover: 0 12px 40px rgba(0, 0, 0, 0.4);
  --modal-shadow: 0 32px 80px rgba(0, 0, 0, 0.5);
}

/* ───── Scrollbar ───── */
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border-color); border-radius: 10px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-faint); }

/* ───── Reset ───── */
*, *::before, *::after { box-sizing: border-box; }

body, html, #root {
  height: 100%;
  margin: 0;
  background: var(--bg);
  color: var(--text-main);
  font-family: var(--font-body);
  font-size: 13.5px;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* ═══════════════════════════════════════
   APP SHELL
═══════════════════════════════════════ */
.app {
  display: flex;
  height: 100vh;
  width: 100vw;
  overflow: hidden;
}

/* ═══════════════════════════════════════
   SIDEBAR
═══════════════════════════════════════ */
.sidebar {
  width: var(--sidebar-width);
  background: var(--sidebar-bg);
  color: rgba(255, 255, 255, 0.85);
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
  border-right: 1px solid var(--sidebar-border);
  overflow-y: auto;
  overflow-x: hidden;
  position: relative;
}

.sidebar-top {
  padding: 20px 16px 8px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 4px 8px;
  margin-bottom: 4px;
}

.logo-box {
  width: 34px;
  height: 34px;
  background: linear-gradient(135deg, var(--primary) 0%, #4338ca 100%);
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.35);
  flex-shrink: 0;
  border: 1px solid rgba(255, 255, 255, 0.12);
}

.logo-box img {
  width: 58%;
  height: 58%;
  object-fit: contain;
  filter: grayscale(1) invert(1);
}

.brand-name {
  font-family: var(--font-title);
  font-size: 16px;
  font-weight: 800;
  color: #fff;
  letter-spacing: -0.4px;
}

.brand-tag {
  font-size: 9px;
  font-weight: 700;
  color: rgba(255,255,255,0.3);
  text-transform: uppercase;
  letter-spacing: 0.8px;
  display: block;
  margin-top: -2px;
}

.sidebar-section-label {
  font-size: 10px;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.25);
  text-transform: uppercase;
  letter-spacing: 1px;
  padding: 16px 24px 6px;
}

.sidebar nav {
  flex: 1;
  padding: 4px 10px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.sidebar nav a {
  display: flex;
  align-items: center;
  gap: 11px;
  color: rgba(255, 255, 255, 0.55);
  padding: 9px 12px;
  border-radius: 9px;
  font-weight: 500;
  font-size: 13.5px;
  cursor: pointer;
  text-decoration: none;
  transition: var(--transition);
  position: relative;
  letter-spacing: -0.1px;
}

.sidebar nav a .nav-icon {
  width: 18px;
  height: 18px;
  flex-shrink: 0;
  opacity: 0.6;
  transition: var(--transition);
}

.sidebar nav a .nav-label { flex: 1; }

.sidebar nav a .nav-badge {
  background: rgba(239, 68, 68, 0.85);
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  border-radius: 20px;
  padding: 1px 6px;
  min-width: 18px;
  text-align: center;
}

.sidebar nav a:hover {
  background: var(--sidebar-item-hover);
  color: rgba(255, 255, 255, 0.9);
}

.sidebar nav a:hover .nav-icon { opacity: 0.9; }

.sidebar nav a.active {
  background: var(--sidebar-item-active);
  color: #fff;
  font-weight: 600;
}

.sidebar nav a.active .nav-icon { opacity: 1; }

.sidebar nav a.active::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 18px;
  background: var(--primary-light);
  border-radius: 0 3px 3px 0;
}

.sidebar-divider {
  height: 1px;
  background: var(--sidebar-border);
  margin: 8px 16px;
}

.sidebar-footer {
  padding: 12px 10px;
  border-top: 1px solid var(--sidebar-border);
  margin-top: auto;
}

.user-card {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 10px;
  border-radius: 10px;
  cursor: pointer;
  transition: var(--transition);
  border: 1px solid transparent;
}

.user-card:hover {
  background: var(--sidebar-item-hover);
  border-color: var(--sidebar-border);
}

.avatar {
  width: 32px;
  height: 32px;
  background: linear-gradient(135deg, var(--primary), #4338ca);
  border-radius: 9px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 12px;
  color: #fff;
  flex-shrink: 0;
  box-shadow: 0 3px 8px rgba(99, 102, 241, 0.25);
}

.user-info { flex: 1; min-width: 0; }

.user-name {
  font-size: 12.5px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.9);
  display: block;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.user-role {
  font-size: 10px;
  color: rgba(255, 255, 255, 0.35);
  text-transform: uppercase;
  font-weight: 700;
  letter-spacing: 0.4px;
}

.logout-icon {
  color: rgba(255, 255, 255, 0.3);
  cursor: pointer;
  transition: var(--transition);
  font-size: 15px;
  padding: 4px;
  border-radius: 6px;
  display: flex;
  align-items: center;
}

.logout-icon:hover {
  color: #f87171;
  background: rgba(239, 68, 68, 0.1);
}

/* ═══════════════════════════════════════
   MAIN CONTENT
═══════════════════════════════════════ */
.main {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  height: 100%;
}

/* ═══════════════════════════════════════
   TOPBAR
═══════════════════════════════════════ */
.topbar {
  height: 58px;
  background: var(--topbar-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
  border-bottom: 1px solid var(--border-color);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  flex-shrink: 0;
  gap: 16px;
}

.page-title {
  font-family: var(--font-title);
  font-size: 14px;
  font-weight: 700;
  color: var(--text-main);
  letter-spacing: -0.3px;
  white-space: nowrap;
}

.page-subtitle {
  font-size: 12px;
  color: var(--text-muted);
  font-weight: 400;
}

.search-container {
  flex: 1;
  max-width: 340px;
  position: relative;
}

.search-container input {
  width: 100%;
  padding: 8px 14px 8px 36px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border-color);
  background: var(--input-bg);
  color: var(--text-main);
  font-size: 13px;
  font-family: inherit;
  outline: none;
  transition: var(--transition);
}

.search-container input:focus {
  border-color: var(--primary);
  background: var(--card-bg);
  box-shadow: 0 0 0 3px var(--primary-glow);
}

.search-container input::placeholder { color: var(--text-muted); }

.search-icon {
  position: absolute;
  left: 11px;
  top: 50%;
  transform: translateY(-50%);
  width: 15px;
  height: 15px;
  color: var(--text-muted);
  pointer-events: none;
}

.top-controls {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.ctrl-btn {
  width: 34px;
  height: 34px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: var(--text-muted);
  transition: var(--transition);
  position: relative;
}

.ctrl-btn svg { width: 16px; height: 16px; }

.ctrl-btn:hover {
  background: var(--bg);
  border-color: var(--primary);
  color: var(--primary);
}

.ctrl-btn .notif-dot {
  position: absolute;
  top: 6px;
  right: 6px;
  width: 6px;
  height: 6px;
  background: var(--error);
  border-radius: 50%;
  border: 1.5px solid var(--card-bg);
}

/* ═══════════════════════════════════════
   CONTENT BODY
═══════════════════════════════════════ */
.content-body {
  flex: 1;
  padding: 24px;
  overflow-y: auto;
  animation: fadeInUp 0.3s ease-out;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(6px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ═══════════════════════════════════════
   NOTIFICATIONS
═══════════════════════════════════════ */
.notifications-container {
  position: fixed;
  bottom: 24px;
  right: 24px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  z-index: 9999;
}

.notification {
  padding: 13px 18px;
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 10px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.15);
  animation: slideInRight 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  max-width: 300px;
  border: 1px solid transparent;
  backdrop-filter: blur(12px);
}

@keyframes slideInRight {
  from { transform: translateX(20px); opacity: 0; }
  to { transform: translateX(0); opacity: 1; }
}

.notification.success { background: rgba(16, 185, 129, 0.95); color: #fff; border-color: rgba(255,255,255,0.15); }
.notification.error { background: rgba(239, 68, 68, 0.95); color: #fff; border-color: rgba(255,255,255,0.15); }
.notification.info { background: rgba(99, 102, 241, 0.95); color: #fff; border-color: rgba(255,255,255,0.15); }
.notification.warning { background: rgba(245, 158, 11, 0.95); color: #fff; border-color: rgba(255,255,255,0.15); }

/* ═══════════════════════════════════════
   DASHBOARD
═══════════════════════════════════════ */
.dashboard-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 4px;
}

.dashboard-greeting {
  font-family: var(--font-title);
  font-size: 20px;
  font-weight: 800;
  color: var(--text-main);
  letter-spacing: -0.5px;
}

.dashboard-date {
  font-size: 12px;
  color: var(--text-muted);
  margin-top: 2px;
}

.dashboard-summary {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
}

@media (max-width: 1100px) { .dashboard-summary { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 640px) { .dashboard-summary { grid-template-columns: 1fr; } }

.summary-card {
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  padding: 18px 20px;
  display: flex;
  align-items: center;
  gap: 14px;
  box-shadow: var(--card-shadow);
  border: 1px solid var(--border-color);
  cursor: pointer;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.summary-card::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, transparent 60%, rgba(99, 102, 241, 0.03));
  pointer-events: none;
  border-radius: inherit;
}

.summary-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--card-shadow-hover);
  border-color: var(--primary);
}

.summary-icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.summary-icon svg { width: 22px; height: 22px; }

.summary-info { display: flex; flex-direction: column; gap: 3px; }

.summary-label {
  font-size: 11px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.6px;
}

.summary-val {
  font-family: var(--font-title);
  font-size: 24px;
  font-weight: 800;
  color: var(--text-main);
  line-height: 1;
}

.summary-change {
  font-size: 11px;
  font-weight: 600;
  color: var(--success);
}

.dashboard-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

@media (max-width: 1100px) { .dashboard-grid { grid-template-columns: 1fr; } }

/* ═══════════════════════════════════════
   CARDS
═══════════════════════════════════════ */
.card {
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  box-shadow: var(--card-shadow);
  padding: 22px 24px;
  border: 1px solid var(--border-color);
  transition: var(--transition);
}

.card:hover { box-shadow: var(--card-shadow-md); }

.card.dark-card {
  background: linear-gradient(140deg, #0f172a 0%, #1e2d50 100%);
  border-color: rgba(99, 102, 241, 0.2);
  color: #fff;
}

[data-theme='light'] .card.dark-card {
  background: linear-gradient(140deg, #0f172a 0%, #1e2d50 100%);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.card-title {
  font-family: var(--font-title);
  font-size: 15px;
  font-weight: 700;
  color: var(--text-main);
  letter-spacing: -0.3px;
}

.card.dark-card .card-title { color: #fff; }

.card-subtitle {
  font-size: 12px;
  color: var(--text-muted);
  margin-top: 2px;
}

.section-label {
  font-size: 10.5px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.8px;
  margin-bottom: 10px;
  display: block;
}

/* Hub Card */
.hub-section { margin: 14px 0; }

.insight-box {
  background: rgba(99, 102, 241, 0.07);
  padding: 14px 16px;
  border-radius: var(--radius-md);
  font-size: 13px;
  line-height: 1.65;
  border-left: 3px solid var(--primary);
  color: var(--text-main);
  border: 1px solid rgba(99, 102, 241, 0.12);
  border-left: 3px solid var(--primary);
}

.card.dark-card .insight-box {
  background: rgba(255,255,255,0.06);
  color: #e2e8f0;
  border-color: rgba(255,255,255,0.08);
  border-left: 3px solid var(--primary-light);
}

.ai-status {
  background: rgba(16, 185, 129, 0.1);
  color: var(--success);
  padding: 12px 14px;
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 12.5px;
  font-weight: 600;
  border: 1px solid rgba(16, 185, 129, 0.15);
  margin-top: 12px;
}

/* Progress Grid */
.progress-grid {
  display: grid;
  grid-template-columns: 1fr 1.2fr;
  gap: 20px;
}

@media (max-width: 768px) { .progress-grid { grid-template-columns: 1fr; } }

.chart-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 140px;
}

.donut-wrapper {
  position: relative;
  width: 110px;
  height: 110px;
}

.donut-svg { width: 110px; height: 110px; transform: rotate(-90deg); }
.donut-bg { fill: none; stroke: var(--border-color); stroke-width: 12; }
.donut-completed { fill: none; stroke: var(--success); stroke-width: 12; stroke-linecap: round; transition: stroke-dashoffset 1s ease; }
.donut-inprogress { fill: none; stroke: var(--primary); stroke-width: 12; stroke-linecap: round; transition: stroke-dashoffset 1s ease; }

.donut-center {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.donut-pct {
  font-family: var(--font-title);
  font-size: 20px;
  font-weight: 800;
  color: var(--text-main);
  line-height: 1;
}

.donut-label { font-size: 9px; color: var(--text-muted); font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; }

.priority-section { display: flex; flex-direction: column; justify-content: center; }

.priority-bars { display: flex; flex-direction: column; gap: 10px; width: 100%; }

.priority-row {
  display: grid;
  grid-template-columns: 68px 1fr 28px;
  align-items: center;
  gap: 10px;
  font-size: 11px;
  font-weight: 700;
  color: var(--text-muted);
}

.progress-bar-bg {
  height: 6px;
  background: var(--bg-alt);
  border-radius: 10px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  border-radius: 10px;
  transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  min-width: 2px;
}

/* Activity Feed */
.activity-feed { display: flex; flex-direction: column; gap: 0; }

.activity-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 12px 0;
  border-bottom: 1px solid var(--border-color);
  position: relative;
}

.activity-item:last-child { border-bottom: none; }

.activity-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
  margin-top: 5px;
}

.activity-content { flex: 1; }
.activity-text { font-size: 13px; color: var(--text-sub); line-height: 1.5; }
.activity-text strong { color: var(--text-main); font-weight: 600; }
.activity-time { font-size: 11px; color: var(--text-muted); margin-top: 2px; }

/* ═══════════════════════════════════════
   BADGES & CHIPS
═══════════════════════════════════════ */
.badge {
  padding: 3px 9px;
  border-radius: var(--radius-full);
  font-size: 10.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  display: inline-block;
  white-space: nowrap;
}

.badge-pending, .badge.in_progress { background: var(--primary-subtle); color: var(--primary); border: 1px solid rgba(99, 102, 241, 0.15); }
.badge-success, .badge.completed { background: var(--success-subtle); color: var(--success); border: 1px solid rgba(16, 185, 129, 0.15); }
.badge-warning, .badge.warning { background: var(--warning-subtle); color: var(--warning); border: 1px solid rgba(245, 158, 11, 0.15); }
.badge-error, .badge.error, .badge.overdue { background: var(--error-subtle); color: var(--error); border: 1px solid rgba(239, 68, 68, 0.15); }
.badge-purple { background: rgba(139, 92, 246, 0.1); color: var(--purple); border: 1px solid rgba(139, 92, 246, 0.15); }
.badge-cyan { background: rgba(6, 182, 212, 0.1); color: var(--cyan); border: 1px solid rgba(6, 182, 212, 0.15); }

/* ═══════════════════════════════════════
   BUTTONS
═══════════════════════════════════════ */
.btn {
  padding: 9px 16px;
  border-radius: var(--radius-sm);
  font-family: var(--font-title);
  font-weight: 600;
  font-size: 12.5px;
  cursor: pointer;
  border: none;
  display: inline-flex;
  align-items: center;
  gap: 7px;
  transition: var(--transition);
  white-space: nowrap;
  letter-spacing: -0.1px;
}

.btn:disabled { opacity: 0.5; cursor: not-allowed; }

.btn-primary {
  background: var(--primary);
  color: #fff;
  box-shadow: 0 2px 8px rgba(99, 102, 241, 0.3);
}

.btn-primary:hover:not(:disabled) {
  background: var(--primary-hover);
  box-shadow: 0 4px 16px rgba(99, 102, 241, 0.4);
  transform: translateY(-1px);
}

.btn-primary:active:not(:disabled) { transform: translateY(0); }

.btn-outline {
  background: transparent;
  border: 1px solid var(--border-color);
  color: var(--text-sub);
}

.btn-outline:hover:not(:disabled) {
  border-color: var(--primary);
  color: var(--primary);
  background: var(--primary-subtle);
}

.btn-ghost {
  background: transparent;
  border: none;
  color: var(--text-muted);
}

.btn-ghost:hover:not(:disabled) {
  background: var(--bg-alt);
  color: var(--text-main);
}

.btn-danger {
  background: var(--error-subtle);
  color: var(--error);
  border: 1px solid rgba(239, 68, 68, 0.15);
}

.btn-danger:hover:not(:disabled) {
  background: var(--error);
  color: #fff;
  box-shadow: 0 4px 12px var(--error-glow);
}

.btn-sm { padding: 6px 12px; font-size: 11.5px; }
.btn-xs { padding: 4px 9px; font-size: 11px; border-radius: var(--radius-xs); }
.btn-icon-only { padding: 8px; }

.btn-spinner {
  width: 13px;
  height: 13px;
  border: 2px solid rgba(255,255,255,0.3);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
  display: inline-block;
}

@keyframes spin { to { transform: rotate(360deg); } }

/* ═══════════════════════════════════════
   TABLES
═══════════════════════════════════════ */
.table-container {
  background: var(--card-bg);
  border-radius: var(--radius-md);
  overflow: hidden;
  box-shadow: var(--card-shadow);
  border: 1px solid var(--border-color);
  width: 100%;
}

.data-table {
  width: 100%;
  border-collapse: collapse;
  text-align: left;
}

.data-table th {
  padding: 12px 18px;
  background: var(--bg);
  color: var(--text-muted);
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  border-bottom: 1px solid var(--border-color);
  white-space: nowrap;
}

.data-table td {
  padding: 13px 18px;
  border-bottom: 1px solid var(--border-color);
  font-size: 13.5px;
  font-weight: 500;
  color: var(--text-main);
  vertical-align: middle;
}

.data-table tbody tr { transition: var(--transition-fast); }

.data-table tbody tr:hover td { background: var(--bg); }

.data-table tr:last-child td { border-bottom: none; }

.table-actions { display: flex; gap: 6px; }

.tbl-btn {
  padding: 5px 11px;
  border-radius: var(--radius-xs);
  font-size: 11.5px;
  font-weight: 600;
  cursor: pointer;
  border: 1px solid var(--border-color);
  background: transparent;
  color: var(--text-muted);
  transition: var(--transition-fast);
  font-family: inherit;
  display: inline-flex;
  align-items: center;
  gap: 5px;
}

.tbl-edit:hover { border-color: var(--primary); color: var(--primary); background: var(--primary-subtle); }
.tbl-del:hover { border-color: var(--error); color: var(--error); background: var(--error-subtle); }

/* ═══════════════════════════════════════
   FORM ELEMENTS
═══════════════════════════════════════ */
input, select, textarea {
  background: var(--input-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  padding: 9px 13px;
  color: var(--text-main);
  font-size: 13.5px;
  font-family: inherit;
  transition: var(--transition);
  width: 100%;
}

input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 3px var(--primary-glow);
  background: var(--card-bg);
}

input::placeholder, textarea::placeholder { color: var(--text-muted); }

select { cursor: pointer; }

textarea { resize: vertical; min-height: 90px; line-height: 1.6; }

label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-sub);
  display: block;
  margin-bottom: 5px;
  letter-spacing: -0.1px;
}

.req { color: var(--error); }

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
}

.form-group { display: flex; flex-direction: column; gap: 5px; }

.form-group.full { grid-column: 1 / -1; }

/* ═══════════════════════════════════════
   MODALS
═══════════════════════════════════════ */
.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(9, 13, 24, 0.6);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 20px;
  animation: fadeIn 0.15s ease;
}

@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

.modal-panel {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-xl);
  width: 100%;
  max-width: 520px;
  max-height: 90vh;
  overflow: hidden;
  box-shadow: var(--modal-shadow);
  animation: modalSlideIn 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  display: flex;
  flex-direction: column;
}

.modal-panel.modal-lg { max-width: 640px; }
.modal-panel.modal-sm { max-width: 400px; }

@keyframes modalSlideIn {
  from { transform: scale(0.94) translateY(8px); opacity: 0; }
  to { transform: scale(1) translateY(0); opacity: 1; }
}

.modal-header {
  padding: 18px 22px 16px;
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
  background: linear-gradient(135deg, var(--primary) 0%, var(--primary-hover) 100%);
}

.modal-header-info { display: flex; align-items: center; gap: 12px; }

.modal-header-icon {
  width: 38px;
  height: 38px;
  background: rgba(255, 255, 255, 0.15);
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 17px;
  color: #fff;
  flex-shrink: 0;
}

.modal-title {
  font-size: 15px;
  font-weight: 700;
  color: #fff;
  letter-spacing: -0.2px;
}

.modal-subtitle {
  font-size: 12px;
  color: rgba(255,255,255,0.65);
  margin-top: 1px;
}

.modal-close-btn {
  width: 30px;
  height: 30px;
  background: rgba(255, 255, 255, 0.15);
  border: none;
  border-radius: 8px;
  color: rgba(255,255,255,0.8);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  transition: var(--transition);
  flex-shrink: 0;
}

.modal-close-btn:hover { background: rgba(255, 255, 255, 0.25); color: #fff; }

.modal-body {
  padding: 20px 22px;
  overflow-y: auto;
  flex: 1;
}

.modal-footer {
  padding: 14px 22px 18px;
  border-top: 1px solid var(--border-color);
  display: flex;
  gap: 10px;
  justify-content: flex-end;
  flex-shrink: 0;
}

/* ═══════════════════════════════════════
   CALENDAR
═══════════════════════════════════════ */
.cal-grid {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  border-radius: var(--radius-md);
  overflow: hidden;
  border: 1px solid var(--border-color);
}

.cal-day-header {
  padding: 10px;
  text-align: center;
  font-size: 11px;
  font-weight: 700;
  color: var(--text-muted);
  background: var(--bg);
  text-transform: uppercase;
  letter-spacing: 0.6px;
  border-bottom: 1px solid var(--border-color);
}

.cal-cell {
  min-height: 88px;
  background: var(--card-bg);
  border: 0.5px solid var(--border-color);
  padding: 7px;
  position: relative;
  transition: var(--transition-fast);
  overflow: hidden;
}

.cal-cell:hover { background: var(--bg); }

.cal-cell.empty-cell { background: var(--bg); opacity: 0.5; }

.cal-date {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
}

.cal-cell.today .cal-date {
  background: var(--primary);
  color: #fff;
  font-weight: 700;
  box-shadow: 0 2px 8px var(--primary-glow);
}

.day-events { display: flex; flex-direction: column; gap: 2px; margin-top: 3px; }

.cal-event-pill {
  padding: 2px 7px;
  border-radius: 4px;
  font-size: 10.5px;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 4px;
  transition: var(--transition-fast);
  white-space: nowrap;
  overflow: hidden;
}

.cal-event-pill:hover { filter: brightness(1.05); }

.cal-event-delete-btn {
  background: none;
  border: none;
  color: inherit;
  opacity: 0;
  cursor: pointer;
  font-size: 13px;
  padding: 0;
  line-height: 1;
  flex-shrink: 0;
  transition: var(--transition-fast);
}

.cal-event-pill:hover .cal-event-delete-btn { opacity: 0.7; }

/* ═══════════════════════════════════════
   PERSONNEL PAGE
═══════════════════════════════════════ */
.personnel-page { display: flex; flex-direction: column; gap: 16px; }

.personnel-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  flex-wrap: wrap;
  gap: 12px;
}

.personnel-subtitle { font-size: 13px; color: var(--text-muted); margin: 2px 0 0; }

.personnel-stats-row {
  display: flex;
  gap: 12px;
  margin-top: 16px;
  flex-wrap: wrap;
}

.pstat-card {
  padding: 10px 16px;
  border-radius: 10px;
  border: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 100px;
}

.pstat-card.pstat-total { background: var(--primary-subtle); border-color: rgba(99, 102, 241, 0.15); }
.pstat-card.pstat-active { background: var(--success-subtle); border-color: rgba(16, 185, 129, 0.15); }
.pstat-card.pstat-inactive { background: var(--error-subtle); border-color: rgba(239, 68, 68, 0.15); }

.pstat-num {
  font-family: var(--font-title);
  font-size: 20px;
  font-weight: 800;
  color: var(--text-main);
}

.pstat-label { font-size: 11px; color: var(--text-muted); font-weight: 600; }

.emp-avatar {
  width: 34px;
  height: 34px;
  border-radius: 9px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 12px;
  color: #fff;
  flex-shrink: 0;
}

.employee-cell { display: flex; align-items: center; gap: 10px; }
.emp-name { font-weight: 600; font-size: 13.5px; }

.personnel-username { font-size: 12.5px; color: var(--text-muted); font-weight: 500; }

.role-pill {
  background: var(--primary-subtle);
  color: var(--primary);
  padding: 3px 9px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 700;
  border: 1px solid rgba(99, 102, 241, 0.12);
}

.personnel-loading,
.personnel-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 56px 24px;
  gap: 8px;
}

.empty-icon { font-size: 40px; margin-bottom: 4px; }
.empty-title { font-size: 16px; font-weight: 700; color: var(--text-main); }
.empty-sub { font-size: 13px; color: var(--text-muted); text-align: center; }

.loading-spinner-lg {
  width: 36px;
  height: 36px;
  border: 3px solid var(--border-color);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  margin-bottom: 8px;
}

/* Personnel Modal form */
.personnel-modal-form { display: flex; flex-direction: column; }
.personnel-modal-scroll { overflow-y: auto; padding: 20px 22px; flex: 1; }

.avatar-preview-row {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 16px;
  background: var(--bg);
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  margin-bottom: 18px;
}

.modal-avatar {
  width: 48px;
  height: 48px;
  border-radius: 13px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 800;
  font-size: 18px;
  color: #fff;
  flex-shrink: 0;
}

.avatar-preview-name { font-weight: 700; font-size: 14.5px; color: var(--text-main); }
.avatar-preview-role { font-size: 12px; color: var(--text-muted); margin-top: 1px; }

.modal-form-grid { display: flex; flex-direction: column; gap: 12px; }

.modal-section-label {
  font-size: 10.5px;
  font-weight: 800;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-top: 6px;
  margin-bottom: 2px;
}

.field-group {
  display: grid;
  grid-template-columns: 36px 1fr;
  align-items: flex-start;
  gap: 10px;
}

.field-group--full { grid-column: 1 / -1; }

.field-icon {
  width: 36px;
  height: 36px;
  background: var(--bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  color: var(--text-muted);
  flex-shrink: 0;
  margin-top: 22px;
}

.field-inner { display: flex; flex-direction: column; gap: 5px; }
.field-label { font-size: 12px; font-weight: 600; color: var(--text-sub); }
.field-input { width: 100%; }

.status-toggle-group { display: flex; gap: 8px; margin-top: 4px; }

.status-pill {
  padding: 6px 16px;
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  border: 1.5px solid var(--border-color);
  background: transparent;
  color: var(--text-muted);
  transition: var(--transition);
  font-family: inherit;
}

.pill-active { background: var(--success-subtle); border-color: var(--success); color: var(--success); }
.pill-inactive { background: var(--error-subtle); border-color: var(--error); color: var(--error); }
.pill-off { background: transparent; }

/* ═══════════════════════════════════════
   PROFILE MODAL
═══════════════════════════════════════ */
.profile-modal {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-xl);
  width: calc(100% - 32px);
  max-width: 460px;
  overflow: hidden;
  box-shadow: var(--modal-shadow);
  animation: modalSlideIn 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}

.profile-modal-avatar {
  font-size: 16px;
  font-weight: 800;
  color: #e0e7ff;
}

.profile-modal-body { padding: 20px 22px; }

.profile-detail-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px 20px;
}

.profile-detail { display: flex; flex-direction: column; gap: 4px; }

.profile-detail-label {
  font-size: 10px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.6px;
}

.profile-detail-value {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-main);
  word-break: break-word;
}

.profile-modal-footer {
  display: flex;
  gap: 10px;
  padding: 14px 22px 18px;
  border-top: 1px solid var(--border-color);
}

.profile-modal-footer .btn { flex: 1; justify-content: center; }

/* ═══════════════════════════════════════
   EACTION PAGE
═══════════════════════════════════════ */
.eaction-page { display: flex; flex-direction: column; gap: 16px; }

.kanban-board {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

@media (max-width: 900px) { .kanban-board { grid-template-columns: 1fr; } }

.kanban-col {
  background: var(--bg);
  border-radius: var(--radius-lg);
  border: 1px solid var(--border-color);
  overflow: hidden;
}

.kanban-col-header {
  padding: 12px 14px;
  display: flex;
  align-items: center;
  gap: 9px;
  border-bottom: 1px solid var(--border-color);
  background: var(--card-bg);
}

.kanban-col-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }

.kanban-col-title {
  font-size: 12.5px;
  font-weight: 700;
  color: var(--text-main);
  letter-spacing: -0.1px;
  flex: 1;
}

.kanban-col-count {
  background: var(--bg-alt);
  color: var(--text-muted);
  font-size: 11px;
  font-weight: 700;
  padding: 1px 7px;
  border-radius: 20px;
  border: 1px solid var(--border-color);
}

.kanban-col-body {
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  min-height: 200px;
  max-height: 480px;
  overflow-y: auto;
}

.action-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 13px 14px;
  cursor: pointer;
  transition: var(--transition);
  position: relative;
}

.action-card:hover {
  box-shadow: var(--card-shadow-md);
  border-color: var(--primary);
  transform: translateY(-1px);
}

.action-card.completed { opacity: 0.6; }

.action-card-title {
  font-size: 13.5px;
  font-weight: 600;
  color: var(--text-main);
  margin-bottom: 8px;
  line-height: 1.4;
}

.action-card.completed .action-card-title {
  text-decoration: line-through;
  color: var(--text-muted);
}

.action-card-meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 10px;
}

.action-meta-chip {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 500;
}

.action-card-footer {
  display: flex;
  gap: 6px;
  margin-top: 8px;
  padding-top: 8px;
  border-top: 1px solid var(--border-color);
}

/* ═══════════════════════════════════════
   EINFO PAGE
═══════════════════════════════════════ */
.einfo-page { display: flex; flex-direction: column; gap: 16px; }

.einfo-layout {
  display: grid;
  grid-template-columns: 240px 1fr;
  gap: 16px;
  align-items: start;
}

@media (max-width: 900px) { .einfo-layout { grid-template-columns: 1fr; } }

.einfo-sidebar-panel { display: flex; flex-direction: column; gap: 12px; }

.einfo-cat-list { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 2px; }

.einfo-cat-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 9px 12px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: 13.5px;
  font-weight: 500;
  color: var(--text-sub);
  transition: var(--transition-fast);
  border: 1px solid transparent;
}

.einfo-cat-item:hover { background: var(--bg-alt); }

.einfo-cat-item.active {
  background: var(--primary-subtle);
  color: var(--primary);
  font-weight: 700;
  border-color: rgba(99, 102, 241, 0.12);
}

.doc-cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 12px;
}

.doc-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 16px;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
}

.doc-card:hover {
  box-shadow: var(--card-shadow-hover);
  border-color: var(--primary);
  transform: translateY(-1px);
}

.doc-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--primary);
  border-radius: var(--radius-lg) var(--radius-lg) 0 0;
  opacity: 0;
  transition: var(--transition);
}

.doc-card:hover::before { opacity: 1; }

.doc-card-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 8px;
}

.doc-card-title {
  font-weight: 700;
  font-size: 13.5px;
  color: var(--text-main);
  line-height: 1.4;
  flex: 1;
}

.doc-card-content {
  font-size: 12.5px;
  color: var(--text-muted);
  line-height: 1.55;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 10px;
}

.doc-card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 6px;
  padding-top: 10px;
  border-top: 1px solid var(--border-color);
}

.doc-card-date { font-size: 11px; color: var(--text-muted); font-weight: 500; }

.note-form-panel {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin-bottom: 14px;
}

.note-form-header {
  padding: 14px 18px;
  background: var(--bg);
  border-bottom: 1px solid var(--border-color);
  font-weight: 700;
  font-size: 13.5px;
  color: var(--text-main);
}

.note-form-body {
  padding: 16px 18px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.note-form-actions {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  padding: 12px 18px;
  border-top: 1px solid var(--border-color);
  background: var(--bg);
}

.markdown-preview {
  background: var(--bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 14px 16px;
  font-size: 13.5px;
  line-height: 1.65;
  color: var(--text-main);
}

.markdown-preview h1, .markdown-preview h2, .markdown-preview h3 {
  font-family: var(--font-title);
  color: var(--text-main);
  margin: 12px 0 6px;
}

.markdown-preview code {
  background: var(--bg-alt);
  border-radius: 4px;
  padding: 1px 5px;
  font-size: 12px;
}

/* ═══════════════════════════════════════
   ETIME PAGE
═══════════════════════════════════════ */
.etime-page { display: flex; flex-direction: column; gap: 16px; }

.etime-header-section {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 12px;
}

.month-title-wrapper { }

.month-title {
  font-family: var(--font-title);
  font-size: 26px;
  font-weight: 800;
  color: var(--text-main);
  letter-spacing: -0.8px;
  line-height: 1;
  margin: 0;
}

.year-subtitle { font-size: 12.5px; color: var(--text-muted); margin-top: 3px; }

.cal-controls {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.segmented-control {
  display: flex;
  background: var(--bg-alt);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  padding: 3px;
  gap: 2px;
}

.segmented-btn {
  padding: 6px 14px;
  border: none;
  border-radius: 6px;
  background: transparent;
  color: var(--text-muted);
  font-size: 11.5px;
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition-fast);
  font-family: inherit;
  letter-spacing: 0.3px;
}

.segmented-btn.active {
  background: var(--card-bg);
  color: var(--text-main);
  box-shadow: 0 1px 4px rgba(0,0,0,0.06);
}

.nav-buttons { display: flex; align-items: center; gap: 6px; }

.nav-btn {
  width: 32px;
  height: 32px;
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: var(--text-sub);
  cursor: pointer;
  font-size: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: var(--transition-fast);
  font-family: inherit;
}

.nav-btn:hover { border-color: var(--primary); color: var(--primary); }

.today-btn {
  padding: 5px 12px;
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: var(--text-sub);
  cursor: pointer;
  font-size: 11.5px;
  font-weight: 700;
  letter-spacing: 0.3px;
  transition: var(--transition-fast);
  font-family: inherit;
}

.today-btn:hover { border-color: var(--primary); color: var(--primary); }

.etime-main-layout {
  display: grid;
  grid-template-columns: 220px 1fr;
  gap: 16px;
  align-items: start;
}

@media (max-width: 900px) { .etime-main-layout { grid-template-columns: 1fr; } }

.etime-sidebar { display: flex; flex-direction: column; gap: 12px; }

.sidebar-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 16px;
}

.sidebar-title {
  font-size: 11.5px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.8px;
  margin-bottom: 10px;
}

.filter-group { display: flex; flex-direction: column; gap: 3px; }

.filter-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--text-sub);
  font-size: 12.5px;
  font-weight: 500;
  cursor: pointer;
  transition: var(--transition-fast);
  font-family: inherit;
  text-align: left;
}

.filter-btn:hover { background: var(--bg); }

.filter-btn.active {
  background: var(--primary-subtle);
  color: var(--primary);
  font-weight: 700;
  border-color: rgba(99, 102, 241, 0.12);
}

.sidebar-stats { display: flex; flex-direction: column; gap: 8px; }

.stat-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12.5px;
  color: var(--text-sub);
  font-weight: 500;
}

.stat-label-wrap { display: flex; align-items: center; gap: 7px; }

.stat-dot { width: 7px; height: 7px; border-radius: 50%; flex-shrink: 0; }

.stat-count {
  font-weight: 700;
  font-size: 13px;
  color: var(--text-main);
  background: var(--bg-alt);
  padding: 1px 7px;
  border-radius: 20px;
  font-family: var(--font-title);
}

.upcoming-widget { }

.upcoming-card {
  background: var(--bg);
  border: 1px solid var(--border-color);
  border-left: 3px solid var(--event-color, var(--primary));
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.upcoming-time { font-size: 11px; color: var(--text-muted); font-weight: 600; }
.upcoming-name { font-size: 13px; font-weight: 700; color: var(--text-main); }
.upcoming-empty { font-size: 12.5px; color: var(--text-muted); text-align: center; padding: 12px 0; }

.calendar-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--card-shadow);
}

/* Timeline */
.etime-list-container { padding: 8px; display: flex; flex-direction: column; gap: 8px; }

.timeline-event-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-left: 3px solid var(--event-color, var(--primary));
  border-radius: var(--radius-md);
  padding: 14px 16px;
  display: flex;
  align-items: flex-start;
  gap: 14px;
  transition: var(--transition);
}

.timeline-event-card:hover { box-shadow: var(--card-shadow-md); border-left-width: 4px; }

.timeline-time-info { min-width: 90px; flex-shrink: 0; }
.timeline-date { font-size: 12px; font-weight: 700; color: var(--text-main); display: block; }
.timeline-time { font-size: 11px; color: var(--text-muted); display: block; margin-top: 2px; }

.timeline-main-content { flex: 1; min-width: 0; }

.timeline-title-wrap { display: flex; align-items: center; flex-wrap: wrap; gap: 7px; margin-bottom: 6px; }

.timeline-title {
  font-size: 14px;
  font-weight: 700;
  color: var(--text-main);
  margin: 0;
  letter-spacing: -0.2px;
}

.type-badge {
  font-size: 10.5px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
  text-transform: capitalize;
  letter-spacing: 0.2px;
}

.priority-badge {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.priority-badge.priority-high { background: var(--error-subtle); color: var(--error); }
.priority-badge.priority-medium { background: var(--warning-subtle); color: var(--warning); }
.priority-badge.priority-low { background: var(--success-subtle); color: var(--success); }

.timeline-desc { font-size: 13px; color: var(--text-muted); margin: 4px 0 8px; line-height: 1.5; }

.timeline-meta { display: flex; flex-wrap: wrap; gap: 12px; }

.meta-item { font-size: 12px; color: var(--text-muted); display: flex; align-items: center; gap: 4px; }

.meta-link { color: var(--primary); text-decoration: none; font-weight: 600; }
.meta-link:hover { text-decoration: underline; }

.timeline-actions { display: flex; gap: 6px; flex-shrink: 0; }

.btn-icon {
  width: 30px;
  height: 30px;
  background: var(--bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  transition: var(--transition-fast);
}

.btn-icon:hover { background: var(--primary-subtle); border-color: var(--primary); }
.btn-icon.btn-delete:hover { background: var(--error-subtle); border-color: var(--error); }

.list-empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 48px;
  gap: 8px;
}

.list-empty-icon { font-size: 36px; margin-bottom: 4px; }
.list-empty-title { font-size: 15px; font-weight: 700; color: var(--text-main); }
.list-empty-subtitle { font-size: 13px; color: var(--text-muted); }

/* ═══════════════════════════════════════
   REPORTS PAGE
═══════════════════════════════════════ */
.reports-page { display: flex; flex-direction: column; gap: 16px; }

.reports-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  flex-wrap: wrap;
  gap: 12px;
}

.metrics-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

@media (max-width: 800px) { .metrics-row { grid-template-columns: 1fr; } }

.metric-card {
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 20px;
  box-shadow: var(--card-shadow);
  transition: var(--transition);
}

.metric-card:hover { box-shadow: var(--card-shadow-hover); transform: translateY(-1px); }

.metric-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 12px;
}

.metric-title {
  font-size: 12px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.metric-value {
  font-family: var(--font-title);
  font-size: 30px;
  font-weight: 800;
  color: var(--text-main);
  line-height: 1;
}

.metric-icon {
  width: 36px;
  height: 36px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.metric-icon svg { width: 18px; height: 18px; }

.metric-bottom { display: flex; align-items: center; justify-content: space-between; gap: 10px; }

.metric-desc { font-size: 12px; color: var(--text-muted); line-height: 1.5; }

.analytics-card { }

.report-block {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 14px;
  background: var(--bg);
  border-radius: var(--radius-sm);
  border: 1px solid var(--border-color);
  margin-bottom: 8px;
  font-size: 13.5px;
}

.anomaly {
  background: rgba(16, 185, 129, 0.08);
  border: 1px solid rgba(16, 185, 129, 0.15);
  color: var(--success);
  padding: 10px 14px;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 14px;
}

/* ═══════════════════════════════════════
   UTILS
═══════════════════════════════════════ */
.panel-controls {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
}

.panel-controls input {
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border-color);
  background: var(--input-bg);
  font-size: 13px;
  width: 200px;
}

.empty {
  text-align: center;
  padding: 40px 24px;
  color: var(--text-muted);
  font-size: 13.5px;
  font-style: italic;
}

.muted { color: var(--text-muted); font-size: 13px; }

.row-completed td { opacity: 0.6; }

.icon-africa { filter: grayscale(1) brightness(0) invert(1); }

/* ═══════════════════════════════════════
   DIGI DELIVERY BTN
═══════════════════════════════════════ */
.btn-digi {
  background: rgba(99, 102, 241, 0.1);
  color: #a5b4fc;
  border: 1px solid rgba(99, 102, 241, 0.2);
  padding: 8px 12px;
  border-radius: 9px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.8px;
  margin: 2px 10px 4px;
  cursor: pointer;
  text-transform: uppercase;
  transition: var(--transition);
  font-family: inherit;
  width: calc(100% - 20px);
}

.btn-digi:hover {
  background: var(--primary);
  color: #fff;
  border-color: var(--primary);
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.3);
}

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');

/* ─── Login Variables ─── */
:root {
  --login-bg-light: #f1f5f9;
  --login-panel-light: #ffffff;
  --login-text-light: #0f172a;
  --login-muted-light: #64748b;
  --login-border-light: #e2e8f0;
  --login-input-bg-light: #f8fafc;

  --login-bg-dark: #070b14;
  --login-panel-dark: #0f1526;
  --login-text-dark: #f1f5f9;
  --login-muted-dark: #94a3b8;
  --login-border-dark: rgba(255,255,255,0.08);
  --login-input-bg-dark: rgba(255,255,255,0.04);

  --lp: #6366f1;
  --lp-dark: #4f46e5;
  --lp-glow: rgba(99, 102, 241, 0.2);
}

/* ─── Light / Dark Vars ─── */
[data-theme='light'] {
  --login-bg: var(--login-bg-light);
  --login-panel: var(--login-panel-light);
  --login-text: var(--login-text-light);
  --login-muted: var(--login-muted-light);
  --login-border: var(--login-border-light);
  --login-input-bg: var(--login-input-bg-light);
  --login-card-border: var(--login-border-light);
}

[data-theme='dark'] {
  --login-bg: var(--login-bg-dark);
  --login-panel: var(--login-panel-dark);
  --login-text: var(--login-text-dark);
  --login-muted: var(--login-muted-dark);
  --login-border: var(--login-border-dark);
  --login-input-bg: var(--login-input-bg-dark);
  --login-card-border: var(--login-border-dark);
}

/* ─── Wrapper ─── */
.login-wrapper {
  min-height: 100vh;
  display: flex;
  background: var(--login-bg);
  position: relative;
  overflow: hidden;
}

/* Background orbs */
.login-bg-decorations { position: absolute; inset: 0; pointer-events: none; overflow: hidden; }

.login-orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(80px);
  opacity: 0.35;
}

.login-orb-1 {
  width: 500px; height: 500px;
  background: radial-gradient(circle, rgba(99,102,241,0.5) 0%, transparent 70%);
  top: -180px; left: -120px;
}

.login-orb-2 {
  width: 380px; height: 380px;
  background: radial-gradient(circle, rgba(139,92,246,0.4) 0%, transparent 70%);
  bottom: -100px; left: 15%;
}

.login-orb-3 {
  width: 300px; height: 300px;
  background: radial-gradient(circle, rgba(99,102,241,0.3) 0%, transparent 70%);
  top: 20%; right: 10%;
}

/* ─── Theme Toggle ─── */
.login-theme-toggle {
  position: fixed;
  top: 20px;
  right: 20px;
  width: 38px;
  height: 38px;
  background: var(--login-panel);
  border: 1px solid var(--login-border);
  border-radius: 10px;
  cursor: pointer;
  font-size: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  transition: all 0.2s ease;
}

.login-theme-toggle:hover {
  box-shadow: 0 4px 14px rgba(99,102,241,0.2);
  border-color: var(--lp);
  transform: translateY(-1px);
}

/* ─── Layout Panels ─── */
.login-panel-left {
  flex: 1;
  background: linear-gradient(150deg, #0b0f1c 0%, #1a1f35 40%, #0f172a 100%);
  display: flex;
  flex-direction: column;
  padding: 40px 48px;
  position: relative;
  overflow: hidden;
}

.login-panel-left::before {
  content: '';
  position: absolute;
  inset: 0;
  background: 
    radial-gradient(circle at 20% 30%, rgba(99,102,241,0.2) 0%, transparent 50%),
    radial-gradient(circle at 80% 70%, rgba(139,92,246,0.15) 0%, transparent 50%);
  pointer-events: none;
}

/* Animated grid overlay */
.login-panel-left::after {
  content: '';
  position: absolute;
  inset: 0;
  background-image: 
    linear-gradient(rgba(99,102,241,0.05) 1px, transparent 1px),
    linear-gradient(90deg, rgba(99,102,241,0.05) 1px, transparent 1px);
  background-size: 40px 40px;
  pointer-events: none;
}

.login-panel-right {
  width: 520px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px 32px;
  background: var(--login-panel);
  position: relative;
  box-shadow: -20px 0 60px rgba(0,0,0,0.08);
}

@media (max-width: 860px) {
  .login-panel-left { display: none; }
  .login-panel-right { width: 100%; box-shadow: none; }
}

/* ─── Left Panel Content ─── */
.login-brand-header {
  display: flex;
  align-items: center;
  gap: 12px;
  position: relative;
  z-index: 1;
}

.login-brand-logo {
  width: 40px;
  height: 40px;
  background: linear-gradient(135deg, var(--lp), var(--lp-dark));
  border-radius: 11px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  box-shadow: 0 4px 14px rgba(99,102,241,0.4);
  border: 1px solid rgba(255,255,255,0.15);
  flex-shrink: 0;
}

.login-brand-logo img {
  width: 58%;
  height: 58%;
  object-fit: contain;
  filter: brightness(0) invert(1);
}

.login-brand-header span {
  font-family: 'Inter', sans-serif;
  font-size: 18px;
  font-weight: 800;
  color: #fff;
  letter-spacing: -0.4px;
}

.login-hero-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  position: relative;
  z-index: 1;
  padding: 20px 0;
}

.login-badge {
  display: inline-block;
  padding: 5px 12px;
  background: rgba(99,102,241,0.15);
  border: 1px solid rgba(99,102,241,0.3);
  border-radius: 20px;
  color: #a5b4fc;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  margin-bottom: 20px;
  width: fit-content;
}

.login-hero-title {
  font-family: 'Inter', sans-serif;
  font-size: 38px;
  font-weight: 800;
  color: #fff;
  line-height: 1.2;
  letter-spacing: -1px;
  margin: 0 0 16px;
}

.login-hero-title span {
  background: linear-gradient(135deg, #818cf8 0%, #a78bfa 50%, #c084fc 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.login-hero-desc {
  font-size: 14.5px;
  color: rgba(255,255,255,0.5);
  line-height: 1.7;
  margin: 0 0 32px;
  max-width: 400px;
}

.login-stats-grid {
  display: flex;
  gap: 12px;
}

.login-stat-card {
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 12px;
  padding: 14px 18px;
  min-width: 130px;
  backdrop-filter: blur(8px);
}

.login-stat-num {
  font-family: 'Inter', sans-serif;
  font-size: 18px;
  font-weight: 800;
  color: #fff;
  letter-spacing: -0.5px;
  margin-bottom: 3px;
}

.login-stat-label {
  font-size: 11px;
  color: rgba(255,255,255,0.4);
  font-weight: 600;
}

/* Feature list */
.login-features {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 24px;
}

.login-feature-item {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 13px;
  color: rgba(255,255,255,0.5);
}

.login-feature-icon {
  width: 24px;
  height: 24px;
  background: rgba(99,102,241,0.15);
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  flex-shrink: 0;
}

.login-brand-footer {
  font-size: 11.5px;
  color: rgba(255,255,255,0.25);
  position: relative;
  z-index: 1;
}

/* ─── Login Card ─── */
.login-card {
  width: 100%;
  max-width: 400px;
}

.login-card-logo-mob {
  display: flex;
  justify-content: center;
  margin-bottom: 20px;
}

.login-card-logo-mob .login-brand-logo {
  width: 44px;
  height: 44px;
}

@media (min-width: 861px) { .login-card-logo-mob { display: none; } }

.login-card-header {
  margin-bottom: 24px;
}

.login-card-title {
  font-family: 'Inter', sans-serif;
  font-size: 24px;
  font-weight: 800;
  color: var(--login-text);
  letter-spacing: -0.6px;
  margin: 0 0 6px;
}

.login-card-subtitle {
  font-size: 14px;
  color: var(--login-muted);
  margin: 0;
  line-height: 1.5;
}

/* ─── Alerts ─── */
.login-alert {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 11px 14px;
  border-radius: 10px;
  font-size: 13px;
  line-height: 1.5;
  margin-bottom: 16px;
  font-weight: 500;
}

.login-alert-icon { font-size: 15px; flex-shrink: 0; margin-top: 1px; }

.login-alert-error {
  background: rgba(239,68,68,0.08);
  border: 1px solid rgba(239,68,68,0.2);
  color: #ef4444;
}

.login-alert-info {
  background: rgba(99,102,241,0.08);
  border: 1px solid rgba(99,102,241,0.2);
  color: var(--lp);
}

/* ─── Login Form ─── */
.login-form {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.login-input-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.login-label {
  font-size: 12.5px;
  font-weight: 700;
  color: var(--login-text);
  letter-spacing: -0.1px;
}

.login-input-container {
  position: relative;
  display: flex;
  align-items: center;
}

.login-input-icon {
  position: absolute;
  left: 12px;
  font-size: 14px;
  pointer-events: none;
  z-index: 1;
  color: var(--login-muted);
}

.login-input {
  width: 100%;
  padding: 11px 44px 11px 38px;
  border: 1.5px solid var(--login-border);
  border-radius: 10px;
  background: var(--login-input-bg);
  color: var(--login-text);
  font-size: 14px;
  font-family: inherit;
  transition: all 0.2s ease;
  outline: none;
}

.login-input:focus {
  border-color: var(--lp);
  box-shadow: 0 0 0 3px var(--lp-glow);
  background: var(--login-panel);
}

.login-input::placeholder { color: var(--login-muted); opacity: 0.7; }

.login-input-eye {
  position: absolute;
  right: 12px;
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  padding: 4px;
  border-radius: 6px;
  transition: all 0.15s ease;
  line-height: 1;
  color: var(--login-muted);
  display: flex;
  align-items: center;
}

.login-input-eye:hover { background: rgba(99,102,241,0.06); color: var(--lp); }

/* ─── Primary Button ─── */
.login-btn-primary {
  width: 100%;
  padding: 13px 20px;
  background: linear-gradient(135deg, var(--lp) 0%, var(--lp-dark) 100%);
  color: #fff;
  border: none;
  border-radius: 11px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 9px;
  transition: all 0.2s ease;
  font-family: inherit;
  letter-spacing: -0.2px;
  box-shadow: 0 4px 14px rgba(99,102,241,0.35);
  margin-top: 4px;
}

.login-btn-primary:hover:not(:disabled) {
  box-shadow: 0 8px 22px rgba(99,102,241,0.45);
  transform: translateY(-1px);
}

.login-btn-primary:active:not(:disabled) { transform: translateY(0); }

.login-btn-primary:disabled { opacity: 0.6; cursor: not-allowed; }

/* ─── Spinner ─── */
.login-spinner {
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255,255,255,0.3);
  border-top-color: #fff;
  border-radius: 50%;
  animation: loginSpin 0.65s linear infinite;
}

@keyframes loginSpin { to { transform: rotate(360deg); } }

/* ─── Demo Section ─── */
.login-demo-section {
  padding-top: 10px;
  border-top: 1px solid var(--login-border);
}

.login-demo-title {
  font-size: 10.5px;
  font-weight: 700;
  color: var(--login-muted);
  text-transform: uppercase;
  letter-spacing: 0.7px;
  text-align: center;
  margin-bottom: 10px;
}

.login-demo-chips {
  display: flex;
  gap: 8px;
  justify-content: center;
  flex-wrap: wrap;
}

.login-demo-chip {
  padding: 7px 16px;
  background: rgba(99,102,241,0.06);
  border: 1.5px solid rgba(99,102,241,0.15);
  border-radius: 20px;
  color: var(--lp);
  font-size: 12.5px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.15s ease;
  font-family: inherit;
}

.login-demo-chip:hover:not(:disabled) {
  background: rgba(99,102,241,0.12);
  border-color: var(--lp);
  transform: translateY(-1px);
}

.login-demo-chip:disabled { opacity: 0.5; cursor: not-allowed; }

/* ─── MFA Inputs ─── */
.login-mfa-container {
  display: flex;
  gap: 9px;
  justify-content: center;
}

.login-mfa-input {
  width: 50px;
  height: 54px;
  text-align: center;
  font-size: 20px;
  font-weight: 800;
  font-family: 'Inter', sans-serif;
  border: 1.5px solid var(--login-border);
  border-radius: 12px;
  background: var(--login-input-bg);
  color: var(--login-text);
  transition: all 0.2s ease;
  outline: none;
}

.login-mfa-input:focus {
  border-color: var(--lp);
  box-shadow: 0 0 0 3px var(--lp-glow);
  background: var(--login-panel);
  transform: scale(1.04);
}

/* ─── Shake Animation ─── */
.login-alert-shake { animation: loginShake 0.5s cubic-bezier(.36,.07,.19,.97); }

@keyframes loginShake {
  0%,100% { transform: translateX(0); }
  20% { transform: translateX(-7px); }
  40% { transform: translateX(7px); }
  60% { transform: translateX(-5px); }
  80% { transform: translateX(5px); }
}

