@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');

:root {
  --lp: #6366f1;
  --lp-dark: #4f46e5;
  --lp-glow: rgba(99, 102, 241, 0.2);
}

[data-theme='light'] {
  --login-bg: #f1f5f9;
  --login-panel: #ffffff;
  --login-text: #0f172a;
  --login-muted: #64748b;
  --login-border: #e2e8f0;
  --login-input-bg: #f8fafc;
  --login-card-border: #e2e8f0;
}

[data-theme='dark'],
:root:not([data-theme='light']) {
  --login-bg: #070b14;
  --login-panel: #0f1526;
  --login-text: #f1f5f9;
  --login-muted: #94a3b8;
  --login-border: rgba(255, 255, 255, 0.08);
  --login-input-bg: rgba(255, 255, 255, 0.04);
  --login-card-border: rgba(255, 255, 255, 0.08);
}

